  let fechasEspeciales = [];

  if (tieneDiaSeleccionado) {
    fechasEspeciales = servicio['_nc_m2m_Servicios_Días Especiales']
      ?.map(i => {
        const fecha = i['Días Especiales']['Día'];
        if (!fecha) return null;

        const [y,m,d] = fecha.split("-");
        return `el ${d}/${m}/${y}`;
      })
      .filter(Boolean) || [];
  }

  const todos = [...diasSemana, ...fechasEspeciales];

  if (todos.length === 0) {
    return "Inválido. El servicio seleccionado no tiene días disponibles para agendar.";
  }

  let lista;

  if (todos.length === 1) {
    lista = todos[0];
  } else if (todos.length === 2) {
    lista = `${todos[0]} y ${todos[1]}`;
  } else {
    lista = `${todos.slice(0,-1).join(', ')} y ${todos[todos.length-1]}`;
  }

  return `Inválido. El servicio seleccionado solo se puede agendar los siguientes días: ${lista}.`;
})()
}}

