// ─── CONFIGURACIÓN ────────────────────────────────────────────────────────────
const TOTAL_SUGERIDOS = 5;
const PASO = 15;
const MARGEN_PREFERIDO = 90;

// ─── INPUTS ──────────────────────────────────────────────────────────────────
const fechaStr = $('When Executed by Another Workflow').first().json.Fecha;
const [datePart] = fechaStr.split('T');
const [year, month, day] = datePart.split('-').map(Number);

const ahoraLuxon = $now.setZone('America/Argentina/Buenos_Aires');
const ahoraMin = ahoraLuxon.hour * 60 + ahoraLuxon.minute;

const inicioHoy = ahoraLuxon.startOf('day');
const finHoy = ahoraLuxon.endOf('day');
const fechaLuxon = ahoraLuxon.set({ year, month, day, hour: 0, minute: 0, second: 0 });
const esHoy = fechaLuxon >= inicioHoy && fechaLuxon <= finHoy;

const duracion = $('Traer Servicio').first().json.Tiempo_estimado_min;
const ocupados = $input.first().json.horasOcupadas;

const dia = $('diaSemana').first().json.diaSemana;
const inicioAtencion = $('Horarios Formateados').first().json[`HoEn-${dia}`];
const finAtencion = $('Horarios Formateados').first().json[`HoSal-${dia}`];
const inicioAlmuerzo = $('Horarios Formateados').first().json[`HoInRec-${dia}`];
const finAlmuerzo = $('Horarios Formateados').first().json[`HoFiRec-${dia}`];

// ─── HELPERS ─────────────────────────────────────────────────────────────────
const aMin = (hhmm) => {
  const [h, m] = hhmm.split(":").map(Number);
  return h * 60 + m;
};
const aHora = (minutos) => {
  const h = Math.floor(minutos / 60).toString().padStart(2, "0");
  const m = (minutos % 60).toString().padStart(2, "0");
  return `${h}:${m}`;
};

// ─── HORARIOS BASE ────────────────────────────────────────────────────────────
const inicioDia = aMin(inicioAtencion);
const finDiaReal = aMin(finAtencion);
const finDia = finDiaReal - duracion;
const almuerzoInicio = aMin(inicioAlmuerzo);
const almuerzoFin = aMin(finAlmuerzo);

// ─── OCUPADOS + BLOQUEADOS ────────────────────────────────────────────────────
const ocupadosMin = ocupados
  .map(o => ({ inicio: aMin(o.inicio), fin: aMin(o.fin) }))
  .sort((a, b) => a.inicio - b.inicio);

const bloqueados = [...ocupadosMin, { inicio: almuerzoInicio, fin: almuerzoFin }]
  .sort((a, b) => a.inicio - b.inicio);

// ─── CURSOR INICIAL ───────────────────────────────────────────────────────────
let cursorInicio = inicioDia;
if (esHoy) {
  const minimoPermitido = ahoraMin + 60;
  cursorInicio = Math.ceil(Math.max(inicioDia, minimoPermitido) / PASO) * PASO;
} else {
  cursorInicio = Math.ceil(inicioDia / PASO) * PASO;
}

// ─── FUNCIÓN: slot libre ──────────────────────────────────────────────────────
const estaLibre = (slotInicio) => {
  const slotFin = slotInicio + duracion;
  for (const bloque of bloqueados) {
    if (slotInicio < bloque.fin && slotFin > bloque.inicio) return false;
  }
  return true;
};

// ─── TODOS LOS SLOTS LIBRES ───────────────────────────────────────────────────
const todosLosSlots = [];
for (let t = cursorInicio; t <= finDia; t += PASO) {
  if (estaLibre(t)) todosLosSlots.push(t);
}

// ─── DISTANCIA DE UN SLOT A UN TURNO OCUPADO ─────────────────────────────────
const distanciaAOcupado = (slotInicio, ocu) => {
  const slotFin = slotInicio + duracion;
  const distAntes = slotFin <= ocu.inicio ? ocu.inicio - slotFin : Infinity;
  const distDespues = slotInicio >= ocu.fin ? slotInicio - ocu.fin : Infinity;
  return Math.min(distAntes, distDespues);
};

// ─── FIX 1: ASIGNAR CADA SLOT AL ÚNICO TURNO MÁS CERCANO ────────────────────
// Evita que slots entre dos turnos cuenten doble y roben cuota
const poolPorOcupado = ocupadosMin.map(() => []);

for (const t of todosLosSlots) {
  const distancias = ocupadosMin.map((ocu, idx) => ({
    idx,
    dist: distanciaAOcupado(t, ocu)
  }));

  const dentroDelMargen = distancias.filter(d => d.dist <= MARGEN_PREFERIDO);
  if (dentroDelMargen.length === 0) continue;

  // Slot va SOLO al pool del turno más cercano (empate → el primero cronológico)
  dentroDelMargen.sort((a, b) => a.dist - b.dist || a.idx - b.idx);
  poolPorOcupado[dentroDelMargen[0].idx].push(t);
}

// ─── FIX 2: DISTRIBUCIÓN PROPORCIONAL SIN Math.max ───────────────────────────
// Sin Math.max(1,...) → muchos turnos no inflan el total de sugeridos
const totalCandidatos = poolPorOcupado.reduce((sum, pool) => sum + pool.length, 0);
const sugeridosSet = new Set();

poolPorOcupado.forEach((pool, idx) => {
  if (pool.length === 0) return;

  const proporcion = pool.length / totalCandidatos;
  const cuota = Math.round(proporcion * TOTAL_SUGERIDOS); // ← sin Math.max(1,...)
  if (cuota === 0) return; // turno con proporción muy chica, otro cercano ya lo cubre

  const ocu = ocupadosMin[idx];
  const ordenados = [...pool].sort((a, b) =>
    distanciaAOcupado(a, ocu) - distanciaAOcupado(b, ocu)
  );

  ordenados.slice(0, cuota).forEach(t => sugeridosSet.add(t));
});

// ─── FIX 3: RECORTE ESTRICTO AL LÍMITE ───────────────────────────────────────
// Por redondeos el Set puede tener 1-2 de más → recortar eliminando los más lejanos
if (sugeridosSet.size > TOTAL_SUGERIDOS) {
  const arr = [...sugeridosSet].sort((a, b) => {
    const distA = Math.min(...ocupadosMin.map(o => distanciaAOcupado(a, o)));
    const distB = Math.min(...ocupadosMin.map(o => distanciaAOcupado(b, o)));
    return distB - distA; // más lejanos primero para eliminar
  });
  sugeridosSet.clear();
  arr.slice(0, TOTAL_SUGERIDOS).forEach(t => sugeridosSet.add(t));
}

// ─── COMPLETAR SI QUEDAMOS CORTOS POR REDONDEO ───────────────────────────────
// Puede pasar que los redondeos bajen a 4 en vez de 5
if (sugeridosSet.size < TOTAL_SUGERIDOS) {
  const restantes = todosLosSlots
    .filter(t => !sugeridosSet.has(t) && poolPorOcupado.some(pool => pool.includes(t)))
    .sort((a, b) => {
      const distA = Math.min(...ocupadosMin.map(o => distanciaAOcupado(a, o)));
      const distB = Math.min(...ocupadosMin.map(o => distanciaAOcupado(b, o)));
      return distA - distB;
    });

  for (const t of restantes) {
    if (sugeridosSet.size >= TOTAL_SUGERIDOS) break;
    sugeridosSet.add(t);
  }
}

// ─── ARMAR LISTA FINAL ────────────────────────────────────────────────────────
const slotsFinales = todosLosSlots.map(t => ({
  horario: sugeridosSet.has(t) ? `${aHora(t)} → Sugerido` : aHora(t)
}));

// ─── INSTRUCCIÓN PARA LA IA ───────────────────────────────────────────────────
const instruccionIA = `Horarios disponibles para el día seleccionado.
Los marcados como "→ Sugerido" son los más convenientes.
REGLA: Ofrecé primero y principalmente los horarios "→ Sugerido". Solo mostrá otros horarios si el cliente los pide explícitamente o los sugeridos no le convienen.
Nunca listes todos los horarios de golpe.`;

return [
  {
    json: {
      slotsDisponibles: slotsFinales,
      instruccionIA
    }
  }
];

