].filter(ancla => ancla >= cursorInicio && ancla <= finDia);

// Para cada ancla, encontrar los slots más cercanos
const SLOTS_POR_ANCLA = Math.ceil(TOTAL_SUGERIDOS / anclas.length);
const sugeridosSet = new Set();

for (const ancla of anclas) {
  if (sugeridosSet.size >= TOTAL_SUGERIDOS) break;

  // Ordenar todos los slots libres por distancia a esta ancla
  const cercanos = [...todosLosSlots]
    .filter(t => !sugeridosSet.has(t))
    .sort((a, b) => Math.abs(a - ancla) - Math.abs(b - ancla));

  cercanos.slice(0, SLOTS_POR_ANCLA).forEach(t => {
    if (sugeridosSet.size < TOTAL_SUGERIDOS) sugeridosSet.add(t);
  });
}

// ─── ARMAR LISTA FINAL ────────────────────────────────────────────────────────
const slotsFinales = todosLosSlots.map(t => ({
  horario: sugeridosSet.has(t) ? `${aHora(t)} → Sugerido` : aHora(t)
}));

// ─── INSTRUCCIÓN PARA LA IA ───────────────────────────────────────────────────
const instruccionIA = `Horarios disponibles para el día seleccionado. No hay turnos reservados aún.
Los marcados como "→ Sugerido" están distribuidos para orientar al cliente.
REGLA: Ofrecé primero los horarios "→ Sugerido". Solo mostrá otros si el cliente los pide o los sugeridos no le convienen.
Nunca listes todos los horarios de golpe.`;

return [
  {
    json: {
      slotsDisponibles: slotsFinales,
      instruccionIA
    }
  }
];
